import React from "react";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import "./TbResists.css";

const DAMAGE_TYPES = ["slash", "pierce", "blunt"] as const;
const RESIST_ORDER = ["ineff", "normal", "fatal"] as const;

const RESIST_LABELS: Record<string, string> = {
    ineff: "Resist",
    normal: "Normal",
    fatal: "Weak",
};

const RESIST_CLASSES: Record<string, string> = {
    ineff: "tb-resists-value--resist",
    normal: "tb-resists-value--normal",
    fatal: "tb-resists-value--weak",
};

export const TbResists = () => {
    const { slots, hover } = useTypedSelector(state => state.tbReducer);
    const combatIdentities = slots
        .filter(slot => slot.role !== "support" && slot.identity)
        .map(slot => slot.identity!);
    const hoveredIdentity = hover?.type === "slot-identity" ? hover.trigger : null;

    const getCounts = (damageType: typeof DAMAGE_TYPES[number]) => {
        return combatIdentities.reduce<Record<string, number>>((result, identity) => {
            const value = String(identity[damageType] || "normal").toLowerCase();
            result[value] = (result[value] || 0) + 1;
            return result;
        }, {});
    };

    return (
        <section className="tb-resists">
            <h2 className="tb-resists-header">Resistance</h2>
            <div className="tb-resists-container">
                {DAMAGE_TYPES.map(damageType => {
                    const counts = getCounts(damageType);
                    const hoveredResist = String(hoveredIdentity?.[damageType] || "").toLowerCase();
                    const visibleKeys = Array.from(new Set([
                        ...RESIST_ORDER,
                        ...Object.keys(counts),
                    ])).filter(key => counts[key]);

                    return (
                        <div className={`tb-resists-type ${hoveredResist ? "tb-resists-type--active" : ""}`} key={damageType}>
                            <img
                                className="tb-resists-img"
                                src={`${process.env.PUBLIC_URL}/images/general/${damageType}.webp`}
                                alt={damageType}
                            />
                            <span className="tb-resists-name">{damageType}</span>
                            <div className="tb-resists-values">
                                {visibleKeys.length ? visibleKeys.map(key => (
                                    <b className={`tb-resists-value ${RESIST_CLASSES[key] || ""} ${hoveredResist === key ? "tb-resists-value--active" : ""}`} key={key}>
                                        {RESIST_LABELS[key] || key} {counts[key]}
                                    </b>
                                )) : (
                                    <b className="tb-resists-value tb-resists-value--empty">0</b>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        </section>
    );
};
