import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { EGOInterface } from "../../../store/reducers/ego-reducer";
import { IdentityInterface } from "../../../store/reducers/ids-reducer";
import { SlotInterface } from "../../../store/reducers/tb-reducer";
import { isFilterMatching } from "../../../tools/isFilterMatching";
import { Filters } from "../../filters/Filters";
import { TbItem } from "../tb-item/TbItem";
import { TbListEGO } from "../tb-list-ego/TbListEgo";
import { TbListIds } from "../tb-list-ids/TbListIds";
import { StatusesInterface } from "../../../store/reducers/statuses-reducer";
import "./TbList.css";

export const TbList = ({
    isIdentityTeamBuilder,
    currentSlot,
}: {
    isIdentityTeamBuilder?: string;
    currentSlot?: SlotInterface | null;
}) => {
    const ids = useQueryClient().getQueryData("identities") as IdentityInterface[] | null;
    const egos = useQueryClient().getQueryData("ego") as EGOInterface[] | null;
    const statuses = useQueryClient().getQueryData('statuses') as StatusesInterface[];
    const [tabOption, settabOption] = useState<"ego" | "identity">("identity");

    const { i18n, t } = useTranslation();
    const { filterState, searchState } = useTypedSelector(state => ({
        filterState: state.filterReducer,
        searchState: state.searchReducer
    }));

    const filterEntities = (entities: any[] | null) => {
        const result: React.ReactNode[] = [];
        const resultNew: React.ReactNode[] = [];

        entities?.forEach(entity => {
            const tier = entity.idTier || entity.egoTier;
            if (!tier || tier.trim() === "") return;

            if (isIdentityTeamBuilder) {
                if (entity.sinner.toLowerCase() !== isIdentityTeamBuilder.toLowerCase()) return;
            }

            if (!isFilterMatching(filterState, searchState, entity, i18n.language, statuses)) return;

            // Передаём currentSlot в TbItem — всегда актуальный слот из Redux
            const item = <TbItem key={entity.imgUrl} entity={entity} currentSlot={currentSlot} />;
            if (!!(+entity.isNew)) resultNew.push(item);
            else result.push(item);
        });

        return { main: result, newItems: resultNew };
    };

    const filteredIds = filterEntities(ids);
    const filteredEgos = filterEntities(egos);

    return (
        <div className="tb-list-container">
            <Filters isIdentityTeamBuilder={isIdentityTeamBuilder} />

            <div style={{ display: "flex", gap: "12px", marginBottom: "4px" }}>
                <span
                    onClick={() => settabOption("identity")}
                    className={`tb-list-header ${tabOption === "identity" ? "tb-list-header--active" : ""}`}
                >
                    {`${t("TbListIds.header")} (${filteredIds.main.length + filteredIds.newItems.length})`}
                    {tabOption === "identity" && <span className="tb-list-header-line" />}
                </span>
                <span
                    onClick={() => settabOption("ego")}
                    className={`tb-list-header ${tabOption === "ego" ? "tb-list-header--active" : ""}`}
                >
                    {`${t("TbListEGO.header")} (${filteredEgos.main.length + filteredEgos.newItems.length})`}
                    {tabOption === "ego" && <span className="tb-list-header-line" />}
                </span>
            </div>

            {tabOption === "identity" ?
                <TbListIds jsxElements={filteredIds.main} jsxElementsNew={filteredIds.newItems} /> :
                <TbListEGO jsxElements={filteredEgos.main} jsxElementsNew={filteredEgos.newItems} />
            }
        </div>
    );
};