import React, { useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { useIntersectionObserver } from '../../hooks/useIntersectionObserver';
import "./ListSinnerBar.css";

interface IListSinnerBarProps {
    data: React.ReactNode[];
    sinner: string;
}

export const ListSinnerBar: React.FC<IListSinnerBarProps> = ({ data, sinner }) => {
    const ref = useRef(null);
    const { isVisible } = useIntersectionObserver(ref, 0.15);
    const { t } = useTranslation();

    // Проверяем, является ли текущий бар новостным
    const isNewsBar = sinner.toLowerCase() === "new";

    return (
        <section ref={ref} className='ListSinnerBar'>
            <header>
                {
                    sinner === "new"
                        ? <div className={`sinner-default-new  ${isVisible && "sinner-default-new--animated"}`}>{t("sinners.new").toUpperCase()}</div>
                        : <img className={`sinner-default-img  ${isVisible && "sinner-default-img--animated"}`} src={`${process.env.PUBLIC_URL}/images/sinners-default/${sinner}.webp`} alt={sinner} />
                }
                <h2 className={`sinner-default-header ${isVisible && "sinner-default-header--animated"}`}>
                    {t(`sinners.${sinner.replace(" ", "")}`)} ({data.length})
                </h2>
            </header>
            <div className={"ListSinnerBar-contentWrapper"}>
                <div className={"ListSinnerBar-content"} >
                    {/* Клонируем элементы данных, чтобы передать им флаг контекста новостей */}
                    {React.Children.map(data, (child) => {
                        if (React.isValidElement(child)) {
                            return React.cloneElement(child as React.ReactElement<any>, { 
                                isNewsContext: isNewsBar 
                            });
                        }
                        return child;
                    })}
                </div>
            </div>
        </section>
    );
};