import React from "react";
import { useTranslation } from "react-i18next";
import { Link, useParams } from "react-router-dom";
import "./MirrorDungeonNav.css";

export const MirrorDungeonNav: React.FC = () => {
    const params = useParams();
    const type = params["type"];
    const { t, i18n } = useTranslation();

    const isReviewer = localStorage.getItem('isReviewer') === 'true';
    const isAdmin = localStorage.getItem('isAdmin') === 'true'; // <-- Добавили проверку

    // Базовые маршруты, доступные всем
    const routes = [
        {
            path: "events",
            name: t("MirrorDungeonNav.events")
        },
        {
            path: "gifts",
            name: t("MirrorDungeonNav.gifts")
        },
        {
            path: "rest-stops",
            name: t("MirrorDungeonNav.rest-stops")
        }
    ];

    if (isReviewer || isAdmin) { // <-- Изменили условие
        routes.unshift({
            path: "themes",
            name: t("MirrorDungeonNav.themes")
        });
    }

    return (
        <div className={"tier-list-nav-container-md"}>
            <nav className={"tier-list-nav-md"}>
                <ul>
                    {
                        routes.map((route) => {
                            return (
                                <li key={`${route.path}`}>
                                    <Link 
                                        className={type === route.path ? "tier-list-nav-md--active" : ""} 
                                        to={`/limbus/${i18n.language}/mirror-dungeon/${route.path}`}
                                    >
                                        {route.name}
                                    </Link>
                                    {type === route.path && <div className="tier-list-nav-line-md" />}
                                </li>
                            )
                        })
                    }
                </ul>
            </nav>
        </div>
    )
}