import { useQuery, UseQueryResult } from "react-query";
import { get, set } from "idb-keyval";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../tools/supabaseClient";

// Твои импорты ключей для валидации
import { idsKeys } from "../constants/idsKeys";
import { egoKeys } from "../constants/egoKeys";
import { md_eventsKeys } from "../constants/md-eventsKeys";
import { md_giftsKeys } from "../constants/md-giftsKeys";

// --- ОБЕРТКИ ДЛЯ СОВМЕСТИМОСТИ (Добавь это в конец файла useFetchByKeys.ts) ---

export const useFetchNewsList = () => useQuery("news_list", () => universalFetcher("news_list"), { staleTime: CACHE_TIME });
export const useFetchMDGifts = () => useQuery("md-gifts", () => universalFetcher("md-gifts"), { staleTime: CACHE_TIME });
export const useFetchChanLog = () => useQuery("chanlog", () => universalFetcher("chanlog"), { staleTime: CACHE_TIME });
export const useFetchIds = () => useQuery("identities", () => universalFetcher("identities"), { staleTime: CACHE_TIME });
export const useFetchEgos = () => useQuery("ego", () => universalFetcher("ego"), { staleTime: CACHE_TIME });
export const useFetchStatuses = () => useQuery("statuses", () => universalFetcher("statuses"), { staleTime: CACHE_TIME });
export const useFetchThemes = () =>useQuery("themes",() => universalFetcher("themes"),{ staleTime: CACHE_TIME });
// Добавь остальные, если они где-то используются индивидуально

const CACHE_TIME = 15 * 60 * 1000; // 15 минут

// --- КОНФИГУРАЦИЯ ТАБЛИЦ ---
export const FETCH_CONFIG: Record<string, any> = {
  identities: {
    endpoint: 'ids',
    validator: (data: any[]) => data.map(row => {
      const item: any = {};
      idsKeys.forEach(({ key, validation }) => {
        const val = row[key] ?? row[key.toLowerCase()] ?? "";
        item[key] = validation(val).validatedVal;
      });
      return item;
    })
  },
  ego: {
    endpoint: 'ego_new',
    order: 'nameEN.asc',
    validator: (data: any[]) => data.map(row => {
      const item: any = {};
      egoKeys.forEach(({ key, validation }) => {
        const val = row[key] ?? row[key.toLowerCase()] ?? "";
        item[key] = validation(val).validatedVal;
      });
      return item;
    })
  },
  "md-events": {
    endpoint: 'md_events',
    order: 'order.asc',
    validator: (data: any[]) => data.map(row => {
      const item: any = {};
      md_eventsKeys.forEach(({ key, validation }) => {
        const val = row[key] ?? row[key.toLowerCase()] ?? (key.includes('choice') ? "{}" : "");
        item[key] = validation(val).validatedVal;
      });
      return item;
    })
  },
  "md-gifts": {
    endpoint: 'md_gifts',
    validator: (data: any[]) => data.map(row => {
      const item: any = {};
      md_giftsKeys.forEach(({ key, validation }) => {
        const val = row[key] ?? row[key.toLowerCase()] ?? "";
        item[key] = validation(val).validatedVal;
      });
      return item;
    })
  },
  news_list: { endpoint: 'news_list' },
  events_list: { endpoint: 'events' },
  chanlog: { endpoint: 'changelog' },
  guides: { endpoint: 'guides', order: 'ids.asc' },
  bingo: { endpoint: 'bingo' },
  themes: { endpoint: 'themes' },
  statuses: { isSpecial: true } // Статусы обрабатываются отдельно ниже
};

// --- ЛОГИКА ЗАГРУЗКИ ---
export const universalFetcher = async (key: string) => {
  const config = FETCH_CONFIG[key];
  if (!config) throw new Error(`Unknown fetch key: ${key}`);

  // 1. Пытаемся взять из IndexedDB
  try {
    const cached = await get(`${key}_cache`);
    if (cached && (Date.now() - cached.timestamp < CACHE_TIME)) {
      return cached.data;
    }
  } catch (e) { console.warn("IDB Read Error", e); }

  // 2. Сама загрузка
  let resultData;
  if (key === "statuses") {
    resultData = await fetchStatusesMerged();
  } else {
    const orderParam = config.order ? `&order=${config.order}` : "";
    const url = `${SUPABASE_URL}/rest/v1/${config.endpoint}?select=*${orderParam}&apikey=${SUPABASE_ANON_KEY}`;
    
    const response = await fetch(url);
    if (!response.ok) throw new Error(`Fetch error: ${response.status}`);
    resultData = await response.json();

    if (config.validator) {
      resultData = config.validator(resultData);
    }
  }

  // 3. Сохраняем в кеш IndexedDB
  try {
    await set(`${key}_cache`, { data: resultData, timestamp: Date.now() });
  } catch (e) { console.warn("IDB Write Error", e); }

  return resultData;
};

// Специальная функция для склейки двух таблиц статусов
async function fetchStatusesMerged() {
  const sinnerUrl = `${SUPABASE_URL}/rest/v1/sinner_statuses?select=*&apikey=${SUPABASE_ANON_KEY}`;
  const anomalyUrl = `${SUPABASE_URL}/rest/v1/anomaly_statuses?select=*&apikey=${SUPABASE_ANON_KEY}`;
  
  const [res1, res2] = await Promise.all([fetch(sinnerUrl), fetch(anomalyUrl)]);
  const data1 = await res1.json();
  const data2 = await res2.json();

  const transform = (items: any[]) => items.map(item => ({
    ...item,
    nameEN: item.nameEN || item.nameen || "",
    owners: typeof item.owners === 'string' ? item.owners.split(',').map((s:any) => s.trim()) : (item.owners || [])
  }));

  return [...transform(data1), ...transform(data2)];
}

// --- ГЛАВНЫЙ ЭКСПОРТ (ХУК) ---
export const useFetchByKeys = (keys: string[]): UseQueryResult<unknown[], unknown>[] => {
  return keys.map((key) => {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    return useQuery(key, () => universalFetcher(key), {
      staleTime: CACHE_TIME,
      cacheTime: Infinity,
      refetchOnWindowFocus: false,
      retry: 2
    });
  }) as UseQueryResult<unknown[], unknown>[];
};