import React, { useEffect, useRef } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { useDispatch } from "react-redux";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { IdentityInterface } from "../../store/reducers/ids-reducer";
import { searchChangeTargetRefAction } from "../../store/reducers/search-reducer";
import { isFilterMatching } from "../../tools/isFilterMatching";
import { ItemEntity } from "../item-entity/ItemEntity";
import { ListSinnerBar } from "../list-sinner-bar/ListSinnerBar";
import { StatusesInterface } from "../../store/reducers/statuses-reducer";
import "./ListIds.css";

export const ListIds: React.FC = () => {
    const containerRef = useRef(null);
    const dispatch = useDispatch();

    const ids = useQueryClient().getQueryData("identities") as IdentityInterface[] | null;
    const statuses = useQueryClient().getQueryData("statuses") as StatusesInterface[];

    const filterState = useTypedSelector(state => state.filterReducer);
    const searchState = useTypedSelector(state => state.searchReducer);

    const { t, i18n } = useTranslation();

    useEffect(() => {
        searchChangeTargetRefAction(dispatch, containerRef);
    }, []);

    const idMap: { [key: string]: React.ReactNode[] } = {
        "new": [],
        "yi sang": [],
        "faust": [],
        "don quixote": [],
        "ryoshu": [],
        "mersault": [],
        "hong lu": [],
        "heathcliff": [],
        "ishmael": [],
        "rodion": [],
        "sinclair": [],
        "outis": [],
        "gregor": [],
    };

    let totalCount = 0;

    const checkStatusUnik = (
        entity: IdentityInterface,
        activeTags: string[]
    ): boolean => {
        if (!entity.statusUnik) return true;

        const [, removePart] = entity.statusUnik
            .split("|")
            .map(part => part.trim());

        const statusesToRemove = removePart
            ? removePart
                  .split("#")
                  .filter(s => s.trim())
                  .map(s => s.trim().toLowerCase())
            : [];

        for (const activeTag of activeTags) {
            if (statusesToRemove.includes(activeTag.toLowerCase())) {
                return false;
            }
        }

        return true;
    };

    if (ids) {
        const rarityWeight: Record<string, number> = {
            OOO: 3,
            OO: 2,
            O: 1,
        };

        const sortedIds = [...ids].sort((a, b) => {
            const rarityA = rarityWeight[a.rarity] || 0;
            const rarityB = rarityWeight[b.rarity] || 0;

            if (rarityB !== rarityA) {
                return rarityB - rarityA;
            }

            return (
                new Date(b.releaseDate).getTime() -
                new Date(a.releaseDate).getTime()
            );
        });

        const activeTags = Object.keys(filterState.types.tags).filter(
            key => filterState.types.tags[key] === true
        );

        for (let i = 0; i < sortedIds.length; i++) {
            const currentID = sortedIds[i];
            const { isNew, imgUrl, sinner, idTier } = currentID;

            const hasValidTier =
                typeof idTier === "string" &&
                idTier
                    .split(",")
                    .some(tier => tier.trim().length > 0);

            if (!hasValidTier) continue;
            if (!checkStatusUnik(currentID, activeTags)) continue;
            if (
                !isFilterMatching(
                    filterState,
                    searchState,
                    currentID,
                    i18n.language,
                    statuses
                )
            ) {
                continue;
            }

            if (!!(+isNew)) {
                idMap.new.push(
                    <ItemEntity
                        hideFooter={true}
                        animationDelay={500}
                        entity={currentID}
                        key={`${imgUrl}-new`}
                    />
                );
            }

            if (sinner in idMap) {
                idMap[sinner].push(
                    <ItemEntity
                        hideFooter={true}
                        animationDelay={500}
                        entity={currentID}
                        key={imgUrl}
                    />
                );
            }

            totalCount++;
        }
    }

    return (
        <section ref={containerRef} className={"list-ids"}>
            <span className={"list-ids-span"}>
                {`${t("ListIds.header")} (${totalCount})`}
            </span>

            {totalCount !== 0 ? (
                Object.entries(idMap).map(([key, value]) => {
                    if (!value.length) return null;

                    return (
                        <ListSinnerBar
                            key={key}
                            sinner={key}
                            data={value}
                        />
                    );
                })
            ) : (
                <p>{t("ListIds.empty")}</p>
            )}
        </section>
    );
};