import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { dmgType, guardType, sinType } from '../../../constants/types';
import { EGOInterface } from '../../../store/reducers/ego-reducer';
import { EntityFullInfoPassiveEGO } from './entity-full-info-passive/EntityFullInfoPassive';
import { EntityFullInfoSkillEGO } from './entity-full-info-skill/EntityFullInfoSkill';
import { UptieComponent } from '../uptie-module/uptie-component';
import { AdminDescription } from '../../test-component/AdminDescription';
import "./EntityFullInfoSkillsEGO.css";

interface IEntityFullInfoProps {
    ego: EGOInterface;
}

export interface ISkillEGO {
    index: number;
    dmgType: (dmgType | guardType)[];
    sin: sinType;
    coins: number;
}

export const EntityFullInfoSkillsEGO: React.FC<IEntityFullInfoProps> = ({ ego }) => {
    const { dmgType, egoSin } = ego;
    const { i18n } = useTranslation();
    const queryClient = useQueryClient();
    const lang = i18n.language.toUpperCase();
    
    const [isAdmin, setIsAdmin] = useState(false);
    const [editConfig, setEditConfig] = useState<any | null>(null);

    useEffect(() => {
        setIsAdmin(localStorage.getItem('isAdmin') === 'true');
    }, []);

    const descriptionPassiveKey = `descriptionPassive${lang}` as keyof typeof ego;
    const rawDescription = ego[descriptionPassiveKey] as string;
    const splitText = rawDescription.split("|");
    const hasPassiveUptie5 = splitText.length > 1 && splitText[1]?.trim().length > 0;
    const hasCoinUptie5 = Boolean(ego.CoinEN5?.trim());
    const hasUptie5 = hasCoinUptie5 || hasPassiveUptie5;

    const maxUptie = hasUptie5 ? 5 : 4;
    const [uptieValue, setUptieValue] = useState(hasUptie5 ? 5 : 4);

    const skill: ISkillEGO = {
        index: 0,
        dmgType: dmgType as (dmgType | guardType)[],
        sin: egoSin as sinType,
        coins: Math.max(...ego.countCoin)
    };

    return (
        <section className="entityFullInfo-skills">
            <UptieComponent
                value={uptieValue}
                setValue={setUptieValue}
                max={maxUptie}
                hasUptie5={hasUptie5}
            />
            
            <div >
                <EntityFullInfoSkillEGO
                    skill={skill}
                    key="ego-skill-main"
                    ego={ego}
                    uptieValue={uptieValue}
                />
            </div>

            <div>
                <EntityFullInfoPassiveEGO ego={ego} />
            </div>

        </section>
    );
};