// components/GameSelectionPage.tsx
import React from 'react';
import { useNavigate } from 'react-router-dom';

export const GameSelectionPage: React.FC = () => {
  const navigate = useNavigate();

  const games = [
    { 
      id: 'limbus', 
      title: 'Limbus Company', 
      img: '/images/limbus_bg.jpg', // Замените на реальные пути
      path: '/limbus/en/' 
    },
    { 
      id: 'umamusume', 
      title: 'Umamusume', 
      img: '/images/uma_bg.jpg', 
      path: '/umamusume/en/' 
    },
  ];

  return (
    <div className="game-grid">
      {games.map((game) => (
        <div 
          key={game.id} 
          className="game-card" 
          onClick={() => navigate(game.path)}
        >
          <img src={game.img} alt={game.title} />
          <div className="title-overlay">{game.title}</div>
        </div>
      ))}
    </div>
  );
};