import React, { useEffect, useState } from 'react';
import './App.css';
import { AppRouter } from './componentslimbus/AppRouter';
import { UmamusumeRouter } from './componentsumamusume/UmamusumeRouter';
import { GameSelectionPage } from './GameSelectionPage';
import { store } from './store/store';
import { Provider } from 'react-redux';
import { BrowserRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import {
  QueryClient,
  QueryClientProvider,
  useQueryClient
} from 'react-query';
import { HelmetProvider } from 'react-helmet-async';
import { del } from 'idb-keyval';
import './i18n';

const queryClient = new QueryClient();

const OldUrlRedirect = () => {
  const location = useLocation();
  const path = location.pathname;

  if (path.startsWith('/limbus') || path.startsWith('/umamusume')) {
    return <Navigate to={`${path}${location.search}`} replace />;
  }

  return <Navigate to={`/limbus${path}${location.search}`} replace />;
};

const ClearCacheButton = () => {
  const queryClient = useQueryClient();

  const clearCacheAndRefresh = async () => {
    try {
      queryClient.clear();

      const cacheKeys = [
        'news_list_cache',
        'md-gifts_cache',
        'chanlog_cache',
        'identities_cache',
        'ego_cache',
        'statuses_cache',
        'events_list_cache',
        'guides_cache',
        'bingo_cache',
        'md-events_cache',
        'themes'
      ];

      await Promise.all(
        cacheKeys.map((key) => del(key))
      );

      cacheKeys.forEach((key) => {
        localStorage.removeItem(key);
        sessionStorage.removeItem(key);
      });
    } catch (error) {
      console.error('Cache clear error:', error);
    }

    window.location.reload();
  };

  return (
    <button
      className="clear-cache-button"
      onClick={clearCacheAndRefresh}
    >
      Clear cache
    </button>
  );
};

function App() {
  const [showButton] = useState(true);

  useEffect(() => {
  const handleKeyDown = async (e: KeyboardEvent) => {
    if (e.ctrlKey && e.shiftKey && e.altKey) {
      e.preventDefault();

      try {
        const cacheKeys = [
          'news_list_cache',
          'md-gifts_cache',
          'chanlog_cache',
          'identities_cache',
          'ego_cache',
          'statuses_cache',
          'events_list_cache',
          'guides_cache',
          'bingo_cache',
          'md-events_cache',
          'themes'
        ];

        await Promise.all(
          cacheKeys.map((key) => del(key))
        );

        cacheKeys.forEach((key) => {
          localStorage.removeItem(key);
          sessionStorage.removeItem(key);
        });
      } catch (error) {
        console.error(error);
      }

      window.location.reload();
    }
  };

  window.addEventListener('keydown', handleKeyDown);

  return () => {
    window.removeEventListener('keydown', handleKeyDown);
  };
}, []);

  return (
    <HelmetProvider>
      <QueryClientProvider client={queryClient}>
        <Provider store={store}>
          <BrowserRouter>
            {showButton && <ClearCacheButton />}

            <Routes>
              <Route
                path="/"
                element={<Navigate to="/limbus/en/" replace />}
              />

              <Route
                path="/select-game"
                element={<GameSelectionPage />}
              />

              <Route
                path="/limbus/*"
                element={<AppRouter />}
              />

              <Route
                path="/umamusume/*"
                element={<UmamusumeRouter />}
              />

              <Route
                path="*"
                element={<OldUrlRedirect />}
              />
            </Routes>
          </BrowserRouter>
        </Provider>
      </QueryClientProvider>
    </HelmetProvider>
  );
}

export default App;