import React from 'react';
import "./EntityFullInfoSkill.css";
import { EGOInterface } from '../../../../store/reducers/ego-reducer';
import { SkillCoinDescription } from "../../../guides/text-formatter/SkillCoinDescription";
import { getAtackWeightBonusFromDescription } from '../../../../tools/getAtackWeightBonusFromDescription';
import { useTranslation } from 'react-i18next';
import { setMobileModalTrigger } from '../../../../store/reducers/mobile-modal-reducer';
import { mobileLayoutFrom } from '../../../../constants/mobileLayoutFrom';
import { useDispatch } from 'react-redux';
import { TooltipMobile } from '../../../tooltip-mobile/TooltipMobile';
import { getUnbreakableCoinBonusFromDescription } from '../../../../tools/getUnbreakableCoinBonusFromDescription';
import { ISkillEGO } from '../EntityFullInfoSkillsEGO';

interface IEntityFullInfoProps {
    ego: EGOInterface;
    skill: ISkillEGO;
    uptieValue: number;
}

export const EntityFullInfoSkillEGO: React.FC<IEntityFullInfoProps> = ({ ego, skill, uptieValue }) => {
    const { imgUrl, basicCoin, weightCoin, growthPerCoin, maxCoinValue, sanity, countCoin, clashCoinValue, damage } = ego;
    const { coins: coinsCount } = skill;
    const { t, i18n } = useTranslation();
    const lang = i18n.language.toUpperCase();
    const dispatch = useDispatch();

    const nameSkillKey = `nameSkill${lang}` as keyof typeof ego;
    const nameSkill = ego[nameSkillKey] as string[];

    const getDynamicDescription = () => {
        let effectiveUptie = uptieValue < 2 ? 2 : uptieValue;
        const getKey = (val: number) => `Coin${lang}${val}` as keyof EGOInterface;
        let description = ego[getKey(effectiveUptie)] as string;

        if (effectiveUptie === 5 && (!description || description.trim() === "")) {
            description = ego[getKey(4)] as string;
        }
        return description || (ego[getKey(2)] as string) || "";
    };

    const descriptionCoin = getDynamicDescription();
    const descriptionPassiveKey = `descriptionPassive${lang}` as keyof typeof ego;
    const descriptionPassive = ego[descriptionPassiveKey] as string;

    const parseSkillDescriptions = (desc: string) => {
        const result = { awakenings: [] as string[], corrosions: [] as string[] };
        if (!desc) return result;
        const cleanedDesc = desc.trim().replace(/^\|+|\|+$/g, '');

        if (cleanedDesc.includes("||")) {
            const parts = cleanedDesc.split("||").map(p => p.trim());
            if (parts[0]) result.awakenings = parts[0].split("|").map(p => p.trim()).filter(p => p.length > 0);
            if (parts[1]) result.corrosions = parts[1].split("|").map(p => p.trim()).filter(p => p.length > 0);
        } else if (cleanedDesc.includes("|")) {
            const parts = cleanedDesc.split("|").map(p => p.trim());
            if (parts[0]) result.awakenings = [parts[0]];
            if (parts[1]) result.corrosions = [parts[1]];
        } else {
            if (cleanedDesc) result.awakenings = [cleanedDesc];
        }
        return result;
    };

    const descriptions = parseSkillDescriptions(descriptionCoin);

    const handleMobileTooltipClick = (tooltip: React.ReactNode) => {
        if (window.innerWidth > mobileLayoutFrom) return;
        setMobileModalTrigger(dispatch, tooltip);
    };

    const getNameForSkill = (type: 'awakening' | 'corrosion', index: number) => {
        if (!nameSkill || nameSkill.length === 0) return "";
        const nameIndex = type === 'awakening' ? index : descriptions.awakenings.length + index;
        if (type === 'corrosion' && (!nameSkill[nameIndex] || nameSkill[nameIndex].trim() === "")) {
            return nameSkill[index] || "";
        }
        return nameSkill[nameIndex] || ""; 
    };

    const getParamValueByUptie = (param: any[], type: 'awakening' | 'corrosion', descIndex: number): number => {
        if (!param || param.length === 0) return 0;

        const globalIndex = type === 'awakening' 
            ? descIndex 
            : descriptions.awakenings.length + descIndex;

        if (!param.some(Array.isArray)) {
            const flatResult = param[globalIndex] !== undefined
                ? param[globalIndex]
                : param[param.length - 1];

            return Number(flatResult) || 0;
        }

        // 1. Получаем массив для текущего аптая (например, [20, 4, 12])
        const uptieData = param[uptieValue - 1] !== undefined 
            ? param[uptieValue - 1] 
            : param[param.length - 1];

        // Если это не массив, просто возвращаем число
        if (!Array.isArray(uptieData)) return Number(uptieData) || 0;

        // 2. Вычисляем сквозной индекс (Global Index)
        // Если это пробуждение (awakening), индекс совпадает с descIndex (0, 1...)
        // Если это искажение (corrosion), индекс = кол-во пробуждений + текущий индекс искажения
        const nestedGlobalIndex = globalIndex;

        // 3. Берем значение по глобальному индексу
        // Если данных в массиве меньше, чем скиллов, берем последнее доступное значение
        const result = uptieData[nestedGlobalIndex] !== undefined 
            ? uptieData[nestedGlobalIndex] 
            : uptieData[uptieData.length - 1];

        return Number(result) || 0;
    };

    const renderSkillSection = (type: 'awakening' | 'corrosion', desc: string, index: number) => {
        // Получаем все параметры с учетом аптая
        const currentBasicCoin = getParamValueByUptie(basicCoin, type, index);
        const currentWeightCoin = getParamValueByUptie(weightCoin, type, index);
        const currentGrowthPerCoin = getParamValueByUptie(growthPerCoin, type, index);
        const currentMaxCoinValue = getParamValueByUptie(maxCoinValue, type, index);
        const currentSanity = getParamValueByUptie(sanity, type, index);
        const currentCountCoin = getParamValueByUptie(countCoin, type, index);
        const currentClashCoinValue = getParamValueByUptie(clashCoinValue, type, index);
        const currentDamage = getParamValueByUptie(damage, type, index);

        const attackWeightBuff = getAtackWeightBonusFromDescription([desc, descriptionPassive]);
        const coins = new Array(currentCountCoin).fill(1);
        const unbreakableCoinBuff = getUnbreakableCoinBonusFromDescription(desc, currentCountCoin);

        const currentDmgType = skill.dmgType[type === 'awakening' ? 0 : 1] || skill.dmgType[0];
        const damageGuardTypeImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/${currentDmgType}.webp`} alt={`${currentDmgType}`} />;
        const sinTypeImgHTML = <img src={`${process.env.PUBLIC_URL}/images/sins/${skill.sin}.webp`} alt={`${imgUrl}`} />;

        const maxCoinBaseValue = Math.sign(currentGrowthPerCoin) === -1
            ? currentBasicCoin
            : currentBasicCoin + currentGrowthPerCoin * currentCountCoin;

        const maxCoinImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/coinBefore.webp`} alt={`${imgUrl}`} />;
        const maxCoinWithConditionImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/coinCondition.webp`} alt={`${imgUrl}`} />;

        const baseDamageBonus = 60;
        const attackDefLevelValue = currentDamage + baseDamageBonus;
        const attackDefLevelImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/damage.webp`} alt={`attack level`} />;

        return (
            <article key={`${type}-${index}`} className="entityFullInfo-skill">
                <div className="entityFullInfo-skill-r">
                    <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: "20px", marginBottom: "15px" }}>
                        <p className={`skill-name ${skill.sin}-sin-color`}>
                            {getNameForSkill(type, index)}
                        </p>

                        <span onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.baseValue")} header={`${currentBasicCoin}`} />)}
                            className="skill-baseCoin tooltip-container coin-text">
                            {currentBasicCoin}
                            <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.baseValue")}</span>
                        </span>

                        <div className="entityFullInfo-coins">
                            <span onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.coinGain")} header={`${currentGrowthPerCoin}`} />)}
                                className="skill-coinGrowth tooltip-container">
                                {Math.sign(currentGrowthPerCoin) === -1 ? "" : "+"}{currentGrowthPerCoin}
                                <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.coinGain")}</span>
                            </span>

                            {coins.map((_, i) => (
                                !unbreakableCoinBuff[i] 
                                    ? <img key={i} src={`${process.env.PUBLIC_URL}/images/general/coin.webp`} alt="coin" /> 
                                    : <img key={i} src={`${process.env.PUBLIC_URL}/images/general/unbreakableCoin.webp`} alt="unbreakableCoin" />
                            ))}
                        </div>
                    </div>

                    <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: "20px", marginBottom: "15px" }}>
                        <div onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.damageType")} image={damageGuardTypeImgHTML} />)}
                            className="skill-atk tooltip-container">
                            {damageGuardTypeImgHTML}
                            <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.damageType")}</span>
                        </div>

                        <div onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.sin")} image={sinTypeImgHTML} />)}
                            className="skill-atk tooltip-container">
                            {sinTypeImgHTML}
                            <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.sin")}</span>
                        </div>

                        <div onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.offenseLevel")} header={`${attackDefLevelValue}`} image={attackDefLevelImgHTML} />)}
                            className="skill-atk tooltip-container">
                            {attackDefLevelValue}
                            {attackDefLevelImgHTML}
                            <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.offenseLevel")}</span>
                        </div>

                        <div onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.maxCoin")} image={maxCoinImgHTML} header={`${maxCoinBaseValue}`} />)}
                            className="skill-atk tooltip-container">
                            {maxCoinBaseValue}
                            {maxCoinImgHTML}
                            <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.maxCoin")}</span>
                        </div>

                        <div onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.coinCondition")} image={maxCoinWithConditionImgHTML} header={`${currentMaxCoinValue}`} />)}
                            className="skill-atk tooltip-container">
                            {currentMaxCoinValue}
                            {t('[')}{currentClashCoinValue}{t(']')}
                            {maxCoinWithConditionImgHTML}
                            <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.coinCondition")}</span>
                        </div>

                        <div style={{ textDecoration: "none" }} className="skill-weight">
                            <span onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.weightBase")} header={`${currentWeightCoin}`} />)}
                                style={{ display: "flex", flexDirection: "row", gap: "5px" }} className="tooltip-container">
                                {new Array(currentWeightCoin).fill(0).map((_, i) => <div key={i} />)}
                                <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.weightBase")}</span>
                            </span>

                            {attackWeightBuff !== 0 && (
                                <span onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.weight")} header={`${currentWeightCoin + attackWeightBuff}`} />)}
                                    style={{ textDecoration: "none", display: "flex", flexDirection: "row", gap: "5px" }} className="skill-weight skill-weight--buffed tooltip-container">
                                    <span>|</span>
                                    {new Array(currentWeightCoin + attackWeightBuff).fill(0).map((_, i) => <div key={i} />)}
                                    <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.weight")}</span>
                                </span>
                            )}
                        </div>
                    </div>
                    <SkillCoinDescription description={desc} />
                </div>
            </article>
        );
    };

    return (
        <>
            {descriptions.awakenings.map((desc, idx) => renderSkillSection('awakening', desc, idx))}
            {descriptions.corrosions.map((desc, idx) => renderSkillSection('corrosion', desc, idx))}
        </>
    );
};
