export const getAtackWeightBonusFromDescription = (descriptions: string[]): number => {
    let result: number = 0;
    
    descriptions.forEach(l => {
        if (!l) return;

        // Обработка ∞Цифра∞ (добавляем бонус веса и удаляем из описания)
        const infinityWeightMatches = l.match(/∞(\d)∞/g); // Изменено с \d+ на \d
        if (infinityWeightMatches) {
            infinityWeightMatches.forEach(match => {
                const weight = parseInt(match.replace(/∞/g, ''), 10);
                result += weight;
            });
        }

        // Оригинальная логика обработки ?growth,maxCount?
        const current = l.replace(/∞d∞/g, '').split("?"); // Удаляем ∞Цифра∞ перед обработкой
        for (let i = 1; i < current.length; i += 2) {
            const currTag = current[i];
            if (!currTag) continue;
            const [growth, maxCount] = currTag.split(",");
            const growthToNumber = Number(growth);
            const maxCountToNumber = Number(maxCount);
            result += (isNaN(growthToNumber) ? 0 : growthToNumber) * (isNaN(maxCountToNumber) ? 1 : maxCountToNumber);
        }
    });
    
    return result;
};

export const cleanDescriptionFromInfinityTags = (description: string): string => {
    return description.replace(/∞d∞/g, '');
};