import { Dispatch } from "redux";

export type UptieState = {
    selectedUptie:1|2|3|4
};

enum UptieActionTypes {
    switch_uptie = "switch_uptie",
    reset_uptie = "reset_uptie",
    set_uptie = "set_uptie" // Added new action type
}

interface switch_uptie {
    type: UptieActionTypes.switch_uptie;
    payload:1|2|3|4
}

interface reset_uptie {
    type: UptieActionTypes.reset_uptie;
}

// Added new action interface
interface set_uptie {
    type: UptieActionTypes.set_uptie;
    payload:1|2|3|4
} 

type UptieAction = switch_uptie | reset_uptie | set_uptie; // Added set_uptie to union type

const initialState : UptieState = {
    selectedUptie:4
};

export const uptieReducer = (state = initialState,action : UptieAction):UptieState =>{
    switch(action.type){
        case UptieActionTypes.switch_uptie:
            return {
                selectedUptie:action.payload
            }
        case UptieActionTypes.reset_uptie:
            return {
                selectedUptie:4
            }
        case UptieActionTypes.set_uptie: // Added new case
            return {
                selectedUptie:action.payload
            }
        default: 
            return state
    }
}

export const uptieResetAction = (dispatch: Dispatch<reset_uptie>) => {
    dispatch({ type: UptieActionTypes.reset_uptie})
}

export const uptieSwitchAction = (dispatch: Dispatch<switch_uptie>,payload:switch_uptie["payload"]) => {
    dispatch({ type: UptieActionTypes.switch_uptie,payload})
}

// Added new action creator
export const setSelectedUptie = (payload: 1|2|3|4) => {
    return {
        type: UptieActionTypes.set_uptie,
        payload
    } as const;
}