import React, { useState, useEffect } from 'react';
import { supabase } from '../../tools/supabaseClient';
import './AdminDescription.css';

interface EditField {
  label: string;
  key: string;
  type: 'text' | 'number' | 'array';
}

interface AdminDescriptionProps {
  entityId: number | string | null;
  tableName: string;
  fields: EditField[];
  isOpen: boolean;
  onClose: () => void;
  onUpdate: () => void;
  isNew?: boolean;
}

// Маппинг таблиц на их уникальное поле идентификатора
const primaryKeyMap: { [key: string]: string } = {
  'ids': 'imgUrl',
  'ego_new': 'imgUrl', 
  'statuses': 'id',
};

export const AdminDescription: React.FC<AdminDescriptionProps> = ({ 
  entityId, 
  tableName, 
  fields, 
  isOpen, 
  onClose, 
  onUpdate, 
  isNew 
}) => {
  const [values, setValues] = useState<any>({});
  const [isLoading, setIsLoading] = useState(false);

  // Определяем, какое поле использовать как ID для текущей таблицы
  const idColumn = primaryKeyMap[tableName] || 'id';

  useEffect(() => {
    if (!isOpen || (!isNew && !entityId)) return;

    const fetchRawData = async () => {
      if (isNew) {
        const empty: any = {};
        fields.forEach(f => { empty[f.key] = ''; });
        setValues(empty);
        return;
      }

      setIsLoading(true);
      try {
        // Используем динамическое имя колонки (idColumn) вместо жесткого 'id'
        const { data, error } = await supabase
          .from(tableName)
          .select('*')
          .eq(idColumn, entityId)
          .single();

        if (error) throw error;
        setValues(data);
      } catch (err: any) {
        alert(`Ошибка получения данных: ${err.message}`);
      } finally {
        setIsLoading(false);
      }
    };

    fetchRawData();
  }, [isOpen, entityId, tableName, isNew, fields, idColumn]);

  const handleSave = async () => {
    let query = supabase.from(tableName);
    let result;

    if (isNew) {
      result = await query.insert([values]);
    } else {
      // Используем динамическое имя колонки при обновлении
      result = await query.update(values).eq(idColumn, entityId);
    }

    if (result.error) {
      alert(`Ошибка: ${result.error.message}`);
    } else {
      onUpdate();
      onClose();
    }
  };

  if (!isOpen) return null;

  return (
    <div className="admin-modal-overlay">
      <div className="admin-modal">
        <h3>Редактирование {tableName}</h3>
        {isLoading ? (
          <div className="modal-loading">Загрузка данных из БД...</div>
        ) : (
          <div className="modal-content">
            {fields.map(field => (
              <div key={field.key}>
                <label>{field.label}</label>
                <textarea 
                  value={values[field.key] ?? ''}
                  onChange={(e) => setValues({...values, [field.key]: e.target.value})}
                />
              </div>
            ))}
            <div className="modal-actions">
              <button onClick={onClose}>Отмена</button>
              <button onClick={handleSave}>Сохранить</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};